import{_ as e,o as r,c as o,a3 as a}from"./chunks/framework.BTFg6ESq.js";const h=JSON.parse('{"title":"角色设定与参数配置 (Personality & Parameters)","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/agents/parameters.md","filePath":"user-guide/tools/llm-chat/agents/parameters.md","lastUpdated":1778239080000}'),l={name:"user-guide/tools/llm-chat/agents/parameters.md"};function s(n,t,i,g,c,d){return r(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="角色设定与参数配置-personality-parameters" tabindex="-1">角色设定与参数配置 (Personality &amp; Parameters) <a class="header-anchor" href="#角色设定与参数配置-personality-parameters" aria-label="Permalink to &quot;角色设定与参数配置 (Personality &amp; Parameters)&quot;">​</a></h1><p>这是 Agent 的“灵魂”所在，通过配置模型、预设消息、关联资源和知识库，定义 Agent 的行为逻辑和知识边界。</p><h2 id="_1-核心设定" tabindex="-1">1. 核心设定 <a class="header-anchor" href="#_1-核心设定" aria-label="Permalink to &quot;1. 核心设定&quot;">​</a></h2><ul><li><strong>模型配置</strong>: 为该 Agent 指定默认的服务渠道（Profile）和模型 ID。你可以为不同 Agent 分配擅长不同领域的模型。</li><li><strong>关联用户档案</strong>: 绑定特定的<a href="./user-profiles">用户档案</a>，在发送请求时自动注入用户姓名、性格、背景等信息，实现个性化交互。</li><li><strong>预设消息 (Presets)</strong>: <ul><li><strong>角色定义</strong>: 支持 <code>system</code> (系统提示)、<code>user</code> (用户示例)、<code>assistant</code> (助手示例)。</li><li><strong>注入策略</strong>: <ul><li><strong>深度 (Depth)</strong>: 控制消息插入到对话历史的深度。</li><li><strong>高级深度</strong>: 支持多点或循环语法（如 <code>3, 10~5</code>），实现极其复杂的上下文排布。</li><li><strong>锚点 (Anchor)</strong>: 将消息固定在上下文的特定位置（如最顶部或最底部）。</li></ul></li><li><strong>开场白显示</strong>: 设置前 N 条预设消息在聊天界面中作为“开场白”展示，方便快速进入状态。</li></ul></li></ul><h2 id="_2-关联资源" tabindex="-1">2. 关联资源 <a class="header-anchor" href="#_2-关联资源" aria-label="Permalink to &quot;2. 关联资源&quot;">​</a></h2><p>Agent 可以通过关联其他子系统来增强能力：</p><ul><li><strong>快捷操作</strong>: 关联<a href="./../quick-actions/index">快捷操作组</a>。激活该 Agent 后，对应的快捷按钮将直接出现在输入框上方。</li><li><strong>世界书 (Worldbook)</strong>: 关联<a href="./../worldbook/index">世界书</a>，实现关键词自动触发背景设定注入。 <ul><li><strong>禁用递归扫描</strong>: 防止世界书条目互相触发导致的上下文爆炸。</li><li><strong>扫描深度</strong>: 控制系统回溯多少条历史消息来匹配关键词。</li></ul></li></ul><h2 id="_3-知识库-rag" tabindex="-1">3. 知识库 (RAG) <a class="header-anchor" href="#_3-知识库-rag" aria-label="Permalink to &quot;3. 知识库 (RAG)&quot;">​</a></h2><p>配置 Agent 访问私有知识库的检索策略。</p><ul><li><strong>检索引擎</strong>: 支持向量检索（Vector）、全文检索（Fulltext）、混合检索（Hybrid）等。</li><li><strong>召回配置</strong>: <ul><li><strong>召回数量</strong>: 每次检索返回的片段数。</li><li><strong>字数上限</strong>: 防止召回内容过多撑破上下文窗口。</li><li><strong>Embedding 模型</strong>: 指定用于计算向量相似度的模型。</li></ul></li><li><strong>结果模板</strong>: 自定义检索结果如何呈现给 LLM，支持 <code>{content}</code>, <code>{score}</code>, <code>{tags}</code> 等变量。</li><li><strong>门控与缓存</strong>: <ul><li><strong>标签门控</strong>: 仅当消息匹配特定标签时才触发检索。</li><li><strong>检索缓存</strong>: 开启后，相似的提问将直接复用之前的检索结果，节省 Token 和时间。</li></ul></li></ul><h2 id="_4-模型高级参数" tabindex="-1">4. 模型高级参数 <a class="header-anchor" href="#_4-模型高级参数" aria-label="Permalink to &quot;4. 模型高级参数&quot;">​</a></h2><p>在「模型参数编辑器」中，你可以精细调整模型的生成行为：</p><ul><li><strong>基础参数</strong>: Temperature (随机性)、Top P、Max Tokens。</li><li><strong>惩罚参数</strong>: Frequency Penalty (频率惩罚)、Presence Penalty (存在惩罚)。</li><li><strong>安全设置</strong>: 配置模型的内容过滤级别（Hate, Harassment, Sexually Explicit 等）。</li><li><strong>后处理 (Post-processing)</strong>: <ul><li><strong>停止词 (Stop Sequences)</strong>: 遇到特定字符串时停止生成。</li><li><strong>逻辑偏置 (Logit Bias)</strong>: 强制模型更多或更少地使用特定 Token。</li></ul></li></ul><hr><h3 id="相关阅读" tabindex="-1">相关阅读 <a class="header-anchor" href="#相关阅读" aria-label="Permalink to &quot;相关阅读&quot;">​</a></h3><ul><li><a href="./../context-pipeline/context-compression">上下文压缩配置</a></li><li><a href="./assets">Agent 资产管理</a></li><li><a href="./../quick-actions/template-syntax">快捷操作模板语法</a></li></ul>',16)])])}const p=e(l,[["render",s]]);export{h as __pageData,p as default};
